local Modules = {
    Colors = {
        ["Green"] = "0,255,0",        -- Vert vif
        ["LightGreen"] = "100,255,100", -- Vert clair
        ["Cyan"] = "0,217,255",       -- Cyan plus clair et lumineux
        ["LightCyan"] = "150,240,255",-- Cyan très clair
        ["Red"] = "255,50,50",        -- Rouge vif
        ["Orange"] = "255,160,0",     -- Orange
        ["Yellow"] = "255,255,0",     -- Jaune
        ["Pink"] = "255,100,200",     -- Rose
        ["Purple"] = "180,80,255",    -- Violet
        ["White"] = "255,255,255",    -- Blanc
        ["Lime"] = "150,255,0",       -- Citron vert
        ["Gold"] = "255,215,0",       -- Doré
        ["Silver"] = "200,200,200",   -- Argenté
    }
}
Modules.ChangeColor = function() 
    game:GetService("RunService").Heartbeat:Connect(function()
    	if game:GetService("CoreGui"):FindFirstChild("DevConsoleMaster") then 
	        for _, v in pairs(game:GetService("CoreGui"):FindFirstChild("DevConsoleMaster"):GetDescendants()) do 
	            if v:IsA("TextLabel") then 
	                v.RichText = true 
	            end 
	        end 
	    end
    end)
end

Modules.print = function(color, text, size)
	if not Modules.Colors[color] then 
		warn("Color was not found!")
		return 
	end 
	
	
    local Text = '<font color="rgb(' .. Modules.Colors[color] .. ')"'
    if size then
        Text = Text .. ' size="' .. tostring(size) .. '"'
    end
    Text = Text .. '>' .. tostring(text) .. '</font>'
    print(Text)
end


Modules.ChangeColor()
--// Examples \\--
Modules.print("Green", "The duplication script loaded succefully")
Modules.print("Cyan", "By RafiLeVrai",20)
Modules.print("Gold","Thank you for buy premium") 





